// solution.go
#include <iostream>
#include <string>
using namespace std;

class Solution {
public:
	string solve(string A, string B) {
		if (A.empty()) {
			return B;
		} else if (B.empty()) {
			return A;
		} else {
			return A + B;
		}
	}
};

int main() {
	ios_base::sync_with_stdio(false);
	cin.tie(NULL);
	Solution s;
	string A, B;
	getline(cin, A);
	getline(cin, B);
	cout << s.solve(A, B) << endl;
	return 0;
}
